import{_ as r,o,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const l=JSON.parse('{"title":"21. Request To Reduce Ordinary Hours","description":"","frontmatter":{"title":"21. Request To Reduce Ordinary Hours","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["hours","employment"]},"headers":[],"relativePath":"ebas/mspp/employment/21-request-to-reduce-ordinary-hours.md","filePath":"ebas/mspp/employment/21-request-to-reduce-ordinary-hours.md"}'),a={name:"ebas/mspp/employment/21-request-to-reduce-ordinary-hours.md"};function n(i,e,d,p,u,m){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="_21-request-to-reduce-ordinary-hours" tabindex="-1">21. Request To Reduce Ordinary Hours <a class="header-anchor" href="#_21-request-to-reduce-ordinary-hours" aria-label="Permalink to &quot;21. Request To Reduce Ordinary Hours&quot;">​</a></h1><p><strong>a.</strong> An Employee may for reasons of family responsibilities or personal health request to reduce their ordinary hours of work on a temporary or permanent basis, for a minimum of 12 months, unless a shorter period is agreed.</p><p><strong>b.</strong> An Employee who intends to reduce their ordinary hours of work will provide the Employer with a written request no less than one month before the date of the proposed change.</p><p><strong>c.</strong> If an Employee’s request to reduce their ordinary hours of work is agreed the Employee will provide the Employer with written confirmation of the proposed change no less than one month, unless a shorter timeframe is agreed, before the date of the proposed change.</p><p><strong>d.</strong> Agreed arrangements for reduced ordinary hours of work will be recorded in accordance with <a href="/eba/ebas/mspp/employment/24-part-time-employment.html">clause 24.2b</a> of the Agreement.</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>e.</strong> This clause 21 is in addition to any entitlement to request flexible working arrangements under the Act or <a href="/eba/ebas/mspp/employment/27-flexible-working-arrangements.html">clause 27</a>.</p><p>Plain language terms: reduce hours request.</p>',8)])])}const c=r(a,[["render",n]]);export{l as __pageData,c as default};
